"use client";

import { useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

type EmployeeOption = { id: string; name: string; nik: string };

export default function TambahGajiKaryawanPage() {
  const router = useRouter();

  const employees: EmployeeOption[] = useMemo(
    () => [
      { id: "u1", name: "Arya Wijaya", nik: "EMP-2023-041" },
      { id: "u2", name: "Budi Nugroho", nik: "EMP-2023-089" },
      { id: "u3", name: "Citra Dewi", nik: "EMP-2022-112" },
    ],
    []
  );

  const [employee, setEmployee] = useState<EmployeeOption | null>(null);
  const [basicSalary, setBasicSalary] = useState<string>("");
  const [effectiveFrom, setEffectiveFrom] = useState<string>(() => {
    const d = new Date();
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const dd = String(d.getDate()).padStart(2, "0");
    return `${yyyy}-${mm}-${dd}`;
  });
  const [isActive, setIsActive] = useState(true);

  function onSubmit() {
    // TODO: POST /employee-basic-salaries
    console.log({
      user_id: employee?.id,
      basic_salary: Number(basicSalary),
      effective_from: effectiveFrom,
      is_active: isActive,
    });

    router.push("/dashboard/manager-hr/gaji-karyawan");
  }

  return (
    <div className="p-6">
      {/* Breadcrumb */}
      <div className="max-w-3xl mx-auto">
        <div className="text-sm text-gray-500 mb-4">
          <button
            onClick={() => router.push("/dashboard/manager-hr")}
            className="hover:text-gray-700"
          >
            Dashboard
          </button>{" "}
          /{" "}
          <button
            onClick={() => router.push("/dashboard/manager-hr/gaji-karyawan")}
            className="hover:text-gray-700"
          >
            Gaji Karyawan
          </button>{" "}
          / <span className="text-gray-700">Tambah Gaji Pokok</span>
        </div>

        <Card className="rounded-2xl shadow-sm">
          <CardContent className="p-0">
            {/* Card header like reference */}
            <div className="px-6 py-5 border-b border-gray-200">
              <div className="flex items-center gap-3">
                <button
                  onClick={() => router.back()}
                  className="h-9 w-9 rounded-lg hover:bg-gray-100 flex items-center justify-center"
                  aria-label="Kembali"
                >
                  <ArrowLeft className="h-5 w-5 text-gray-700" />
                </button>

                <div>
                  <h1 className="text-lg font-bold text-gray-900">
                    Tambah Gaji Pokok
                  </h1>
                  <p className="text-sm text-gray-600">
                    Tambahkan basic salary untuk karyawan.
                  </p>
                </div>
              </div>
            </div>

            {/* Form body */}
            <div className="px-6 py-6 space-y-5">
              {/* Karyawan */}
              <div className="space-y-2">
                <Label className="text-xs font-semibold tracking-wide text-gray-700 uppercase">
                  Karyawan
                </Label>

                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button
                      variant="outline"
                      className="w-full justify-between rounded-xl"
                    >
                      {employee
                        ? `${employee.name} (${employee.nik})`
                        : "Pilih karyawan"}
                      <span className="text-gray-400">▼</span>
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent className="w-[--radix-dropdown-menu-trigger-width]">
                    {employees.map((e) => (
                      <DropdownMenuItem key={e.id} onClick={() => setEmployee(e)}>
                        {e.name} ({e.nik})
                      </DropdownMenuItem>
                    ))}
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>

              {/* Gaji pokok */}
              <div className="space-y-2">
                <Label className="text-xs font-semibold tracking-wide text-gray-700 uppercase">
                  Gaji Pokok (Rp)
                </Label>
                <Input
                  value={basicSalary}
                  onChange={(e) => setBasicSalary(e.target.value)}
                  placeholder="Contoh: 7500000"
                  className="rounded-xl"
                  inputMode="numeric"
                />
                <p className="text-xs text-gray-500">
                  Simpan sebagai angka tanpa titik/koma. (Mis. 7500000)
                </p>
              </div>

              {/* Effective From */}
              <div className="space-y-2">
                <Label className="text-xs font-semibold tracking-wide text-gray-700 uppercase">
                  Effective From
                </Label>
                <Input
                  type="date"
                  value={effectiveFrom}
                  onChange={(e) => setEffectiveFrom(e.target.value)}
                  className="rounded-xl"
                />
              </div>

              {/* Status aktif */}
              <div className="space-y-2">
                <Label className="text-xs font-semibold tracking-wide text-gray-700 uppercase">
                  Status Aktif
                </Label>

                <label className="flex items-center gap-3 rounded-xl border border-gray-200 p-3 cursor-pointer select-none">
                  <input
                    type="checkbox"
                    className="h-4 w-4"
                    checked={isActive}
                    onChange={(e) => setIsActive(e.target.checked)}
                  />
                  <span className="text-sm text-gray-700">
                    {isActive ? "Active" : "Inactive"}
                  </span>
                </label>

                <p className="text-xs text-gray-500">
                  Catatan: 1 karyawan hanya boleh punya 1 basic salary yang aktif.
                </p>
              </div>
            </div>

            {/* Footer actions like reference */}
            <div className="px-6 py-4 border-t border-gray-200 flex items-center justify-end gap-3">
              <Button
                variant="outline"
                className="rounded-xl"
                onClick={() => router.push("/dashboard/manager-hr/gaji-karyawan")}
              >
                Batal
              </Button>

              <Button
                className="rounded-xl bg-blue-600 hover:bg-blue-700 text-white"
                onClick={onSubmit}
                disabled={!employee || !basicSalary}
              >
                Simpan Gaji
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}